payload.text:
I will refine the `OrderList` interface by adjusting the column widths, highlighting the product quantity, and making the action buttons ("Chuẩn bị hàng", "In đơn") more prominent within the order card.

Here are the updated files:

# Updated files:

## components/OrderList.tsx

- **Grid Layout Update**: Adjusted the column distribution to **5 (Product) - 2 (Note) - 2 (Financials) - 3 (Shipping & Actions)**.
- **Product Quantity**: Increased size and visibility (Red text, larger font) to make it stand out.
- **Action Buttons**: Added prominent buttons for "Chuẩn bị hàng" (Prepare) and "In đơn" (Print) directly in the "Shipping & Actions" column for orders in the 'processing' state.
- **Visual Improvements**: Tweaked spacing and alignment to fit the new layout.

```tsx
import React, { useState, useEffect, useMemo } from 'react';
import { MOCK_ORDERS, MOCK_PRODUCTS, INITIAL_INTEGRATIONS } from '../services/mockData';
import { RefreshCw, Search, Printer, MessageSquare, Package, Truck, Zap, ChevronLeft, ChevronRight, ShoppingBag, Lock, Plus, X, User, MapPin, Store, Layers, FileOutput, Split, CheckSquare, Clock, XCircle, RotateCcw, AlertTriangle, MessageSquareQuote, ArrowDownWideNarrow } from 'lucide-react';
import { Platform, UserProfile, Order, Product, OrderItem } from '../types';

interface OrderListProps {
  user: UserProfile;
}

const LOGOS: Record<string, string> = {
  [Platform.SHOPEE]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fe/Shopee.svg/2560px-Shopee.svg.png',
  [Platform.LAZADA]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4d/Lazada_%282019%29.svg/1200px-Lazada_%282019%29.svg.png',
  [Platform.TIKTOK]: 'https://upload.wikimedia.org/wikipedia/en/thumb/a/a9/TikTok_logo.svg/2560px-TikTok_logo.svg.png',
  [Platform.FACEBOOK]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b8/2021_Facebook_icon.svg/2048px-2021_Facebook_icon.svg.png',
  [Platform.WOOCOMMERCE]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/WooCommerce_logo.svg/1200px-WooCommerce_logo.svg.png',
};

const CARRIER_LOGOS: Record<string, string> = {
  'SPX Express': 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fe/Shopee.svg/2560px-Shopee.svg.png',
  'J&T Express': 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7d/J%26T_Express_logo.svg/2560px-J%26T_Express_logo.svg.png',
  'Giao Hàng Nhanh': 'https://upload.wikimedia.org/wikipedia/commons/4/45/GHN_Logistics_Logo.png', 
  'Viettel Post': 'https://upload.wikimedia.org/wikipedia/commons/0/08/Viettel_Post_logo.png',
  'Ninja Van': 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/25/Ninja_Van_logo.svg/1200px-Ninja_Van_logo.svg.png',
  'Giao hàng thủ công': ''
};

const getCarrierLogo = (name: string) => {
  if (CARRIER_LOGOS[name]) return CARRIER_LOGOS[name];
  if (name.includes('J&T')) return CARRIER_LOGOS['J&T Express'];
  if (name.includes('Viettel')) return 'https://upload.wikimedia.org/wikipedia/vi/0/08/Logo_Viettel_Post.png';
  if (name.includes('Nhanh')) return 'https://cdn.haitrieu.com/wp-content/uploads/2022/05/Logo-GHN-Slogan-En.png';
  return null;
};

const PlatformIcon = ({ platform }: { platform: Platform | 'Manual' }) => {
  if (platform === 'Manual') {
    return (
      <span className="text-indigo-600 font-bold text-[10px] bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100 flex items-center gap-1">
        <Package size={10} /> Manual
      </span>
    );
  }

  const logoUrl = LOGOS[platform];
  if (logoUrl) {
    return <img src={logoUrl} alt={platform} className="h-5 w-auto object-contain" />;
  }

  return <span className="text-slate-500 font-bold text-[10px]">{platform}</span>;
};

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

const parseDate = (dateStr?: string): Date | null => {
  if (!dateStr) return null;
  const parts = dateStr.split(' ');
  if (parts.length !== 2) return null;

  const timeParts = parts[0].split(':');
  const dateParts = parts[1].split('/');

  if (timeParts.length !== 2 || dateParts.length !== 3) return null;

  const hour = parseInt(timeParts[0]);
  const minute = parseInt(timeParts[1]);
  const day = parseInt(dateParts[0]);
  const month = parseInt(dateParts[1]) - 1;
  const year = parseInt('20' + dateParts[2]);

  return new Date(year, month, day, hour, minute);
};

type OrderStatus = 'all' | 'pending' | 'processing' | 'shipping' | 'delivered' | 'cancelled' | 'returned';
type ProcessingSubStatus = 'all' | 'unprocessed' | 'printed' | 'packed';
type SortOption = 'newest' | 'oldest' | 'deadline_asc' | 'deadline_desc';

const OrderList: React.FC<OrderListProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<OrderStatus>('processing');
  const [subTab, setSubTab] = useState<ProcessingSubStatus>('unprocessed');
  const [searchTerm, setSearchTerm] = useState('');
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);

  const [selectedPlatform, setSelectedPlatform] = useState<Platform | 'all'>('all');
  const [selectedShop, setSelectedShop] = useState<string>('all');
  const [selectedCarrier, setSelectedCarrier] = useState<string>('all');
  const [showExpressOnly, setShowExpressOnly] = useState(false);

  const [sortOption, setSortOption] = useState<SortOption>('deadline_asc');

  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());

  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [newOrderItems, setNewOrderItems] = useState<{product: Product, quantity: number}[]>([]);
  const [customerInfo, setCustomerInfo] = useState({ name: '', phone: '', address: '' });
  const [productSearch, setProductSearch] = useState('');

  const [isBulkPrintModalOpen, setIsBulkPrintModalOpen] = useState(false);
  const [isSplitOrderModalOpen, setIsSplitOrderModalOpen] = useState(false);
  const [bulkPrintIncludeExpress, setBulkPrintIncludeExpress] = useState(true);

  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const tabs: { id: OrderStatus; label: string; count?: number }[] = [
    { id: 'all', label: 'Tất cả' },
    { id: 'pending', label: 'Chờ xác nhận', count: 1 },
    { id: 'processing', label: 'Chờ lấy hàng', count: 5 },
    { id: 'shipping', label: 'Đang giao' },
    { id: 'delivered', label: 'Đã giao' },
    { id: 'cancelled', label: 'Đã hủy', count: 1 },
    { id: 'returned', label: 'Trả Hàng / Hoàn Tiền' }
  ];

  const subTabs: { id: ProcessingSubStatus; label: string }[] = [
    { id: 'all', label: 'Tất cả' },
    { id: 'unprocessed', label: 'Chưa Xử Lý' },
    { id: 'printed', label: 'Đã In Đơn' },
    { id: 'packed', label: 'Đã Đóng Gói' }
  ];

  const availableCarriers = useMemo(() => {
    const carriers = new Set<string>();
    orders.forEach(o => {
      if (o.shippingCarrier) carriers.add(o.shippingCarrier);
    });
    return Array.from(carriers);
  }, [orders]);

  useEffect(() => {
    setCurrentPage(1);
    setSelectedOrderIds(new Set());
    if (activeTab === 'processing') setSortOption('deadline_asc');
    else setSortOption('newest');
  }, [activeTab, subTab, searchTerm, selectedPlatform, selectedShop, showExpressOnly, selectedCarrier]);

  const availableShops = useMemo(() => {
    let shops: { id: string, name: string, platform: Platform }[] = [];
    INITIAL_INTEGRATIONS.forEach(integration => {
      if (selectedPlatform === 'all' || integration.platform === selectedPlatform) {
        integration.shops.forEach(shop => {
           shops.push({ id: shop.id, name: shop.name, platform: integration.platform });
        });
      }
    });
    return shops;
  }, [selectedPlatform]);

  const accessibleOrders = useMemo(() => {
    if (user.role === 'collaborator') {
      return orders.filter(o => user.assignedShopIds.includes(o.shopId));
    }
    return orders;
  }, [user, orders]);

  const filteredOrders = accessibleOrders.filter(order => {
    if (activeTab !== 'all' && order.status !== activeTab) return false;
    if (activeTab === 'processing' && subTab !== 'all') {
       if (order.subStatus !== subTab) return false;
    }
    if (selectedPlatform !== 'all' && order.platform !== selectedPlatform) return false;
    if (selectedShop !== 'all' && order.shopId !== selectedShop) return false;
    if (selectedCarrier !== 'all' && order.shippingCarrier !== selectedCarrier) return false;
    if (showExpressOnly && order.shippingMethod !== 'Hỏa tốc') return false;
    if (searchTerm) {
       const term = searchTerm.toLowerCase();
       return (
         order.id.toLowerCase().includes(term) || 
         order.customerName.toLowerCase().includes(term) ||
         order.items.some(item => item.name.toLowerCase().includes(term))
       );
    }
    return true;
  }).sort((a, b) => {
    if (sortOption === 'newest' || sortOption === 'oldest') {
      const dateA = parseDate(a.date)?.getTime() || 0;
      const dateB = parseDate(b.date)?.getTime() || 0;
      return sortOption === 'newest' ? dateB - dateA : dateA - dateB;
    } else {
      const dateA = parseDate(a.shipByDate)?.getTime() || Number.MAX_VALUE;
      const dateB = parseDate(b.shipByDate)?.getTime() || Number.MAX_VALUE;
      return sortOption === 'deadline_asc' ? dateA - dateB : dateB - dateA;
    }
  });

  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredOrders.slice(indexOfFirstItem, indexOfLastItem);
  const totalPages = Math.ceil(filteredOrders.length / itemsPerPage);

  const expressOrdersCount = accessibleOrders.filter(o => o.shippingMethod === 'Hỏa tốc' && (activeTab === 'all' || o.status === activeTab)).length;

  const handleAddProductToOrder = (product: Product) => {
    setNewOrderItems(prev => {
      const existing = prev.find(i => i.product.id === product.id);
      if (existing) {
        return prev.map(i => i.product.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { product, quantity: 1 }];
    });
    setProductSearch('');
  };

  const handleRemoveItem = (id: string) => {
    setNewOrderItems(prev => prev.filter(i => i.product.id !== id));
  };

  const handleCreateOrder = () => {
    if (!customerInfo.name || newOrderItems.length === 0) {
      alert("Vui lòng nhập tên khách hàng và chọn ít nhất 1 sản phẩm.");
      return;
    }

    const items: OrderItem[] = newOrderItems.map(i => ({
      productId: i.product.id,
      name: i.product.name,
      image: i.product.image,
      sku: i.product.sku,
      variant: 'Default',
      quantity: i.quantity,
      price: i.product.salePrice || i.product.price
    }));

    const subTotal = items.reduce((sum, i) => sum + i.price * i.quantity, 0);
    const shippingFee = 30000;
    const total = subTotal + shippingFee;

    const newOrder: Order = {
      id: `MANUAL-${Date.now()}`,
      customerName: customerInfo.name,
      customerPhone: customerInfo.phone,
      address: customerInfo.address,
      platform: 'Manual',
      shopId: 'manual_shop',
      date: new Date().toLocaleString('vi-VN'),
      shipByDate: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000).toLocaleString('vi-VN'),
      total,
      shippingFee,
      platformFee: 0,
      tax: 0,
      profit: total - shippingFee,
      status: 'pending',
      items,
      isCOD: true,
      shippingCarrier: 'Giao hàng thủ công',
      shippingMethod: 'Tiêu chuẩn'
    };

    setOrders([newOrder, ...orders]);
    setIsCreateModalOpen(false);
    setNewOrderItems([]);
    setCustomerInfo({ name: '', phone: '', address: '' });
  };

  const toggleSelectOrder = (id: string) => {
    const newSelected = new Set(selectedOrderIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    setSelectedOrderIds(newSelected);
  };

  const toggleSelectAll = () => {
    if (selectedOrderIds.size === currentItems.length) {
      setSelectedOrderIds(new Set());
    } else {
      setSelectedOrderIds(new Set(currentItems.map(o => o.id)));
    }
  };

  const handleBulkPrint = () => {
    if (selectedOrderIds.size === 0) return alert('Vui lòng chọn ít nhất 1 đơn hàng');
    setBulkPrintIncludeExpress(true); 
    setIsBulkPrintModalOpen(true);
  };

  const handleSplitOrder = () => {
    if (selectedOrderIds.size === 0) return alert('Vui lòng chọn ít nhất 1 đơn hàng');
    setIsSplitOrderModalOpen(true);
  };

  const renderShippingStatus = (order: Order) => {
    const carrierLogo = order.shippingCarrier ? getCarrierLogo(order.shippingCarrier) : null;

    if (order.status === 'pending') {
      return (
        <div className="flex flex-col items-center justify-center space-y-2">
           <span className="text-xs text-slate-400 italic">Chưa chọn ĐVVC</span>
           <button className="bg-indigo-600 text-white text-xs px-3 py-1.5 rounded hover:bg-indigo-700 transition-colors shadow-sm">
             Xác nhận đơn
           </button>
        </div>
      );
    }

    if (order.status === 'processing') {
      const deadlineDate = parseDate(order.shipByDate);
      const now = new Date();
      const isLate = deadlineDate && deadlineDate < now;
      const isNearDeadline = deadlineDate && deadlineDate < new Date(now.getTime() + 24 * 60 * 60 * 1000) && !isLate;

      return (
        <div className="flex flex-col items-center justify-center space-y-2 w-full">
           <div className="flex items-center gap-2">
              {carrierLogo ? (
                <img src={carrierLogo} alt={order.shippingCarrier} className="h-6 object-contain" title={order.shippingCarrier} />
              ) : (
                <div className="text-sm font-bold text-slate-800 text-center">{order.shippingCarrier}</div>
              )}
              {order.trackingCode && <div className="text-xs font-mono text-slate-500 bg-slate-100 px-1 rounded">{order.trackingCode}</div>}
           </div>

           <div className="bg-orange-50 text-orange-700 px-2 py-1 rounded text-xs font-medium flex items-center gap-1 border border-orange-100 whitespace-nowrap">
             <Clock size={12} /> Chưa nhận hàng
           </div>

           {order.shipByDate && (
             <div className={`text-[10px] px-2 py-0.5 rounded border flex items-center gap-1 w-full justify-center ${isLate ? 'bg-red-50 text-red-600 border-red-100 font-bold' : isNearDeadline ? 'bg-orange-50 text-orange-600 border-orange-100' : 'bg-slate-50 text-slate-500 border-slate-100'}`}>
                {isLate && <AlertTriangle size={10} />}
                <span>Hạn: {order.shipByDate}</span>
             </div>
           )}

           {/* Prominent Action Buttons */}
           <div className="flex gap-2 w-full mt-1">
              <button 
                className="flex-1 bg-white border border-slate-300 text-slate-700 text-xs py-1.5 rounded hover:bg-slate-50 font-medium transition-colors flex items-center justify-center gap-1"
                title="In phiếu giao hàng"
              >
                <Printer size={14} /> In đơn
              </button>
              <button 
                className="flex-1 bg-indigo-600 text-white text-xs py-1.5 rounded hover:bg-indigo-700 font-medium transition-colors shadow-sm flex items-center justify-center gap-1"
                title="Chuẩn bị hàng"
              >
                <Package size={14} /> Chuẩn bị
              </button>
           </div>
        </div>
      );
    }

    if (order.status === 'shipping') {
      return (
        <div className="flex flex-col items-center justify-center space-y-2">
           {carrierLogo ? (
             <img src={carrierLogo} alt={order.shippingCarrier} className="h-6 object-contain mb-1" title={order.shippingCarrier} />
           ) : (
             <div className="text-sm font-bold text-slate-800 text-center">{order.shippingCarrier}</div>
           )}
           <div className="bg-blue-50 text-blue-700 px-2 py-1 rounded text-xs font-medium flex items-center gap-1 border border-blue-100 whitespace-nowrap animate-pulse">
             <Truck size={12} /> Đang giao
           </div>
           <div className="text-xs text-indigo-600 font-medium hover:underline cursor-pointer font-mono">{order.trackingCode}</div>
        </div>
      );
    }

    if (order.status === 'delivered') {
      return (
        <div className="flex flex-col items-center justify-center space-y-2">
           {carrierLogo ? (
             <img src={carrierLogo} alt={order.shippingCarrier} className="h-6 object-contain mb-1" title={order.shippingCarrier} />
           ) : (
             <div className="text-sm font-bold text-slate-800 text-center">{order.shippingCarrier}</div>
           )}
           <div className="bg-green-50 text-green-700 px-2 py-1 rounded text-xs font-medium flex items-center gap-1 border border-green-100 whitespace-nowrap">
             <CheckSquare size={12} /> Đã giao
           </div>
           <div className="text-xs text-slate-400 font-mono">{order.trackingCode}</div>
        </div>
      );
    }

    // Cancelled / Returned / etc...
    return (
        <div className="flex flex-col items-center justify-center space-y-2">
           {carrierLogo ? (
             <img src={carrierLogo} alt={order.shippingCarrier} className="h-6 object-contain mb-1 grayscale opacity-60" title={order.shippingCarrier} />
           ) : (
             order.shippingCarrier && <div className="text-sm font-bold text-slate-400 text-center line-through">{order.shippingCarrier}</div>
           )}
           <div className={`px-2 py-1 rounded text-xs font-medium flex items-center gap-1 border whitespace-nowrap ${order.status === 'returned' ? 'bg-yellow-50 text-yellow-700 border-yellow-100' : 'bg-red-50 text-red-700 border-red-100'}`}>
             {order.status === 'returned' ? <RotateCcw size={12} /> : <XCircle size={12} />}
             {order.status === 'returned' ? 'Đang trả hàng' : 'Đã hủy'}
           </div>
        </div>
    );
  };

  return (
    <div className="space-y-4 font-sans text-slate-800 flex flex-col h-full animate-fade-in pb-10">
      <div className="flex justify-between items-center mb-2 shrink-0">
         <div className="flex items-center gap-3">
           <h2 className="text-2xl font-bold">Đơn Hàng</h2>
           {user.role === 'collaborator' && (
             <span className="text-xs bg-yellow-100 text-yellow-800 px-2 py-1 rounded border border-yellow-200 flex items-center gap-1">
               <Lock size={12} /> Giới hạn shop
             </span>
           )}
         </div>
         <div className="flex gap-2">
            <button 
              onClick={() => setIsCreateModalOpen(true)}
              className="flex items-center gap-2 px-3 py-1.5 bg-green-600 text-white rounded-md text-sm font-medium hover:bg-green-700 transition-colors shadow-sm"
            >
              <Plus size={14} /> Tạo đơn hàng
            </button>
            <button 
              className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white rounded-md text-sm font-medium hover:bg-indigo-700 transition-colors shadow-sm"
              title="Cập nhật trạng thái đơn hàng mới nhất từ các sàn"
            >
              <RefreshCw size={14} /> Đồng bộ
            </button>
         </div>
      </div>

      {/* Main Tabs */}
      <div className="bg-white rounded-t-lg border-b border-slate-200 sticky top-0 z-10 shadow-sm shrink-0">
        <div className="flex overflow-x-auto no-scrollbar">
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`whitespace-nowrap px-6 py-4 text-sm font-medium border-b-2 transition-all flex items-center gap-2 ${
                activeTab === tab.id
                  ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50'
                  : 'border-transparent text-slate-500 hover:text-indigo-600 hover:bg-slate-50'
              }`}
            >
              {tab.label}
              {tab.count ? <span className="bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full shadow-sm">{tab.count}</span> : null}
            </button>
          ))}
        </div>
      </div>

      {/* Sub Tabs & Filters */}
      <div className="bg-white rounded-b-lg shadow-sm border border-slate-100 p-4 space-y-4 shrink-0 transition-all">
         {activeTab === 'processing' && (
           <div className="flex gap-2 mb-4 border-b border-slate-100 pb-4 overflow-x-auto">
              {subTabs.map(st => (
                <button
                  key={st.id}
                  onClick={() => setSubTab(st.id)}
                  className={`px-4 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap ${
                    subTab === st.id 
                    ? 'bg-indigo-600 border-indigo-600 text-white shadow-sm' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300 hover:text-indigo-600'
                  }`}
                >
                  {st.label}
                </button>
              ))}
           </div>
         )}

         <div className="flex flex-col xl:flex-row gap-4 justify-between items-start xl:items-center">
            {/* Action Buttons */}
            {activeTab === 'processing' && (
                <div className="flex gap-2 w-full xl:w-auto overflow-x-auto">
                <button className="px-4 py-2 bg-indigo-600 text-white rounded-md text-sm font-medium shadow-sm hover:bg-indigo-700 flex items-center gap-2 transition-colors whitespace-nowrap" title="Xác nhận và chuẩn bị các đơn đã chọn">
                    <Package size={16} /> Chuẩn bị hàng loạt
                </button>
                <button 
                    onClick={handleBulkPrint}
                    className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-md text-sm font-medium hover:bg-slate-50 hover:border-indigo-200 flex items-center gap-2 transition-colors whitespace-nowrap" 
                    title="In phiếu giao hàng hàng loạt"
                    >
                    <Printer size={16} /> In đơn hàng loạt
                </button>
                <button 
                    onClick={handleSplitOrder}
                    className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-md text-sm font-medium hover:bg-slate-50 hover:border-indigo-200 flex items-center gap-2 transition-colors whitespace-nowrap"
                    >
                    <Split size={16} /> Chia đơn
                </button>
                </div>
            )}

            {activeTab !== 'processing' && <div className="hidden xl:block"></div>}

            {/* Filter Section */}
            <div className="flex flex-col sm:flex-row gap-2 w-full xl:w-auto ml-auto flex-wrap justify-end">

               {/* Express Toggle */}
               <button 
                 onClick={() => setShowExpressOnly(!showExpressOnly)}
                 className={`flex items-center gap-2 px-3 py-2 border rounded-lg text-sm font-medium transition-colors whitespace-nowrap ${
                   showExpressOnly 
                   ? 'bg-red-50 border-red-200 text-red-600 shadow-sm' 
                   : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                 }`}
               >
                 <Zap size={16} className={showExpressOnly ? "fill-red-600" : ""} />
                 Hỏa Tốc
                 <span className="bg-red-100 text-red-600 text-[10px] px-1.5 py-0.5 rounded-full ml-1">{expressOrdersCount}</span>
               </button>

               {/* Carrier Select */}
               <div className="relative min-w-[130px]">
                  <Truck className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <select 
                    value={selectedCarrier}
                    onChange={(e) => setSelectedCarrier(e.target.value)}
                    className="w-full pl-9 pr-8 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer hover:border-indigo-300"
                  >
                    <option value="all">Vận chuyển</option>
                    {availableCarriers.map(c => (
                      <option key={c} value={c}>{c}</option>
                    ))}
                  </select>
               </div>

               {/* Sort Select */}
               <div className="relative min-w-[150px]">
                  <ArrowDownWideNarrow className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <select 
                    value={sortOption}
                    onChange={(e) => setSortOption(e.target.value as SortOption)}
                    className="w-full pl-9 pr-8 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer hover:border-indigo-300"
                  >
                    <option value="newest">Mới nhất</option>
                    <option value="oldest">Cũ nhất</option>
                    <option value="deadline_asc">Hạn giao: Trễ → Sớm</option>
                    <option value="deadline_desc">Hạn giao: Sớm → Trễ</option>
                  </select>
               </div>

               {/* Platform Select */}
               <div className="relative min-w-[130px]">
                  <Layers className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <select 
                    value={selectedPlatform}
                    onChange={(e) => {
                      setSelectedPlatform(e.target.value as Platform | 'all');
                      setSelectedShop('all');
                    }}
                    className="w-full pl-9 pr-8 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer hover:border-indigo-300"
                  >
                    <option value="all">Tất cả sàn</option>
                    {Object.values(Platform).map(p => (
                      <option key={p} value={p}>{p}</option>
                    ))}
                    <option value="Manual">Đơn ngoài</option>
                  </select>
               </div>

               {/* Shop Select */}
               <div className="relative min-w-[140px]">
                  <Store className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                  <select 
                    value={selectedShop}
                    onChange={(e) => setSelectedShop(e.target.value)}
                    className="w-full pl-9 pr-8 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer hover:border-indigo-300"
                  >
                    <option value="all">Tất cả shop</option>
                    {selectedPlatform === 'all' ? (
                       Object.values(Platform).map(platform => {
                          const platformShops = availableShops.filter(s => s.platform === platform);
                          if (platformShops.length === 0) return null;
                          return (
                            <optgroup key={platform} label={platform}>
                               {platformShops.map(shop => (
                                 <option key={shop.id} value={shop.id}>{shop.name}</option>
                               ))}
                            </optgroup>
                          );
                       })
                    ) : (
                       availableShops.map(shop => (
                         <option key={shop.id} value={shop.id}>{shop.name}</option>
                       ))
                    )}
                  </select>
               </div>

               {/* Search Input */}
               <div className="relative w-48 group">
                 <input 
                    type="text" 
                    placeholder="Tìm mã, tên..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-shadow group-hover:bg-white"
                 />
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-hover:text-indigo-500 transition-colors" size={16} />
               </div>
            </div>
         </div>
      </div>

      {/* Order List */}
      <div className="space-y-4 flex-1">
         {/* Header Row for large screens */}
         <div className="hidden lg:grid grid-cols-12 gap-4 px-4 py-2 bg-slate-100 rounded-lg text-xs font-semibold text-slate-500 uppercase">
            {/* Product column */}
            <div className="col-span-5 flex items-center gap-4">
              <div className="w-8 flex justify-center">
                 <input type="checkbox" checked={selectedOrderIds.size === currentItems.length && currentItems.length > 0} onChange={toggleSelectAll} className="rounded w-4 h-4 text-indigo-600 focus:ring-indigo-500 border-slate-300" />
              </div>
              <span>Sản phẩm / Thông tin đơn</span>
            </div>
            {/* Note Column */}
            <div className="col-span-2 text-left">Ghi chú</div>
            <div className="col-span-2 text-center">Tài chính</div>
            <div className="col-span-3 text-center">Vận chuyển & Thao tác</div>
         </div>

         {currentItems.length === 0 ? (
           <div className="text-center py-20 bg-white rounded-xl border border-dashed border-slate-300">
              <ShoppingBag size={48} className="mx-auto text-slate-300 mb-3" />
              <p className="text-slate-500">Không tìm thấy đơn hàng nào phù hợp.</p>
              {user.role === 'collaborator' && <p className="text-xs text-yellow-600 mt-2">Lưu ý: Bạn chỉ thấy đơn hàng của các shop được phân công.</p>}
           </div>
         ) : (
           currentItems.map(order => {
             // Calculate Financials
             const importCost = order.total - order.shippingFee - order.platformFee - order.tax - order.profit;
             const importCostPct = order.total > 0 ? (importCost / order.total * 100).toFixed(1) : '0.0';

             return (
             <div 
               key={order.id} 
               className={`bg-white border rounded-xl shadow-sm hover:shadow-md transition-shadow duration-300 overflow-hidden group 
                 ${selectedOrderIds.has(order.id) ? 'border-indigo-300 ring-1 ring-indigo-300' : 'border-slate-200'}
                 ${order.shippingMethod === 'Hỏa tốc' ? 'bg-red-50/10 border-l-4 border-l-red-500' : ''}
               `}
             >
                {/* Card Header */}
                <div className="px-4 py-3 border-b border-slate-100 flex justify-between items-center bg-slate-50/30 group-hover:bg-indigo-50/20 transition-colors">
                   <div className="flex items-center gap-3">
                      <input 
                        type="checkbox" 
                        checked={selectedOrderIds.has(order.id)} 
                        onChange={() => toggleSelectOrder(order.id)}
                        className="w-4 h-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500 cursor-pointer" 
                      />
                      <div className="flex items-center gap-2">
                         <span className="font-bold text-sm text-slate-800 hover:text-indigo-600 cursor-pointer transition-colors" title="Xem hồ sơ khách hàng">{order.customerName}</span>
                         <PlatformIcon platform={order.platform} />
                         <span className="text-slate-400 text-xs">|</span>
                         <span className="text-xs text-slate-500 flex items-center gap-1 cursor-pointer hover:text-indigo-600 transition-colors" title="Sao chép mã đơn hàng">
                           {order.id} 
                         </span>
                      </div>
                   </div>
                   <div className="flex items-center gap-4 text-xs">
                      <span className="text-slate-500">{order.date}</span>
                      {order.subStatus === 'unprocessed' && <span className="text-orange-600 font-medium bg-orange-50 px-2 py-0.5 rounded">Chưa xử lý</span>}
                      {order.subStatus === 'printed' && <span className="text-blue-600 font-medium bg-blue-50 px-2 py-0.5 rounded">Đã in</span>}
                      {order.subStatus === 'packed' && <span className="text-green-600 font-medium bg-green-50 px-2 py-0.5 rounded">Đã đóng gói</span>}
                      {order.shippingMethod === 'Hỏa tốc' && (
                        <span className="flex items-center gap-1 text-red-600 font-bold bg-red-50 px-2 py-0.5 rounded border border-red-100 animate-pulse">
                          <Zap size={10} fill="currentColor" /> Hỏa tốc
                        </span>
                      )}

                      <div className="flex gap-2 ml-4">
                         <button className="text-slate-400 hover:text-indigo-600 transition-colors" title="Chat với khách"><MessageSquare size={14} /></button>
                      </div>
                   </div>
                </div>

                {/* Card Body */}
                <div className="p-4 grid grid-cols-1 lg:grid-cols-12 gap-4 items-center">

                   {/* Products - Takes up 5 columns */}
                   <div className="lg:col-span-5 space-y-4">
                      {order.items.map((item, idx) => (
                        <div key={idx} className="flex gap-4 items-start">
                           <div className="w-32 h-32 rounded-lg border border-slate-200 overflow-hidden shrink-0 group-hover:border-indigo-200 transition-colors shadow-sm bg-slate-100">
                              <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                           </div>
                           <div className="flex-1 min-w-0 flex flex-col justify-center py-1">
                              <h4 className="text-sm font-bold text-slate-800 line-clamp-2 hover:text-indigo-600 cursor-pointer transition-colors" title={item.name}>{item.name}</h4>
                              <div className="flex flex-wrap gap-2 mt-2">
                                <span className="text-xs text-slate-500 bg-slate-100 px-2 py-1 rounded border border-slate-200">SKU: {item.sku}</span>
                                <span className="text-xs text-slate-500 bg-slate-100 px-2 py-1 rounded border border-slate-200">PL: {item.variant}</span>
                              </div>
                              <div className="flex items-center gap-3 mt-3">
                                 <span className="text-lg font-bold text-red-600 bg-red-50 px-3 py-1 rounded border border-red-100">x{item.quantity}</span>
                                 <span className="text-sm font-bold text-indigo-700">{formatCurrency(item.price)}</span>
                              </div>
                           </div>
                        </div>
                      ))}
                      {order.items.length > 2 && (
                         <div className="text-center text-xs text-slate-400 italic hover:text-slate-600 cursor-pointer pt-2">
                            + {order.items.length - 2} sản phẩm khác
                         </div>
                      )}
                   </div>

                   {/* Note Column - 2 cols */}
                   <div className="lg:col-span-2 text-sm text-slate-600 border-l border-r lg:border-r-0 border-slate-100 px-2 h-full flex flex-col justify-center">
                      {order.note ? (
                        <div className="bg-yellow-50 border border-yellow-100 p-2 rounded text-xs text-yellow-800 italic relative">
                            <MessageSquareQuote size={12} className="absolute top-1 right-1 opacity-50"/>
                            "{order.note}"
                        </div>
                      ) : (
                        <span className="text-slate-400 text-xs italic opacity-50 text-center">Không có ghi chú</span>
                      )}
                   </div>

                   {/* Financials - 2 cols */}
                   <div className="lg:col-span-2 text-sm lg:border-l border-slate-100 px-4 space-y-1 h-full flex flex-col justify-center bg-slate-50/30">
                      <div className="flex justify-between items-center text-xs">
                        <span className="text-slate-500">Tổng thu:</span>
                        <span className="font-bold text-indigo-700">{formatCurrency(order.total)}</span>
                      </div>

                      <div className="flex justify-between items-center text-xs">
                         <span className="text-slate-400">Giá vốn:</span>
                         <div className="flex gap-1">
                            <span className="text-slate-500">-{formatCurrency(importCost)}</span>
                            <span className="text-[10px] text-slate-400">({importCostPct}%)</span>
                         </div>
                      </div>

                      <div className="flex justify-between items-center text-xs">
                         <span className="text-slate-400">Phí sàn:</span>
                         <div className="flex gap-1">
                            <span className="text-red-500">-{formatCurrency(order.platformFee)}</span>
                            <span className="text-[10px] text-slate-400">({(order.platformFee / order.total * 100).toFixed(1)}%)</span>
                         </div>
                      </div>

                      <div className="flex justify-between items-center text-xs">
                         <span className="text-slate-400">Thuế:</span>
                         <div className="flex gap-1">
                            <span className="text-red-500">-{formatCurrency(order.tax)}</span>
                            <span className="text-[10px] text-slate-400">({(order.tax / order.total * 100).toFixed(1)}%)</span>
                         </div>
                      </div>

                      <div className="border-t border-slate-200 pt-1 mt-1 flex justify-between items-center text-xs">
                         <span className="font-bold text-slate-600">Lãi:</span>
                         <div className="flex gap-1">
                            <span className={`font-bold ${order.profit > 0 ? 'text-green-600' : 'text-red-600'}`}>
                              {formatCurrency(order.profit)}
                            </span>
                            <span className="text-[10px] text-slate-400 font-normal">
                              ({order.total > 0 ? (order.profit / order.total * 100).toFixed(1) : 0}%)
                            </span>
                         </div>
                      </div>
                      <div className="text-center mt-1">
                        {order.isCOD && <div className="text-[10px] font-bold text-green-600 bg-green-50 inline-block px-2 py-0.5 rounded border border-green-100">COD</div>}
                      </div>
                   </div>

                   {/* Shipping & Actions - 3 cols */}
                   <div className="lg:col-span-3 h-full flex flex-col justify-center border-l border-slate-100 px-4">
                      {renderShippingStatus(order)}
                   </div>
                </div>
             </div>
           )})
         )}
      </div>

       {/* Pagination Footer */}
       {filteredOrders.length > 0 && (
          <div className="px-6 py-4 border-t border-slate-100 flex items-center justify-between bg-white rounded-b-lg mt-4 shrink-0 shadow-sm">
             <div className="text-sm text-slate-500">
               Hiển thị <span className="font-medium">{indexOfFirstItem + 1}</span> đến <span className="font-medium">{Math.min(indexOfLastItem, filteredOrders.length)}</span> trong tổng số <span className="font-medium">{filteredOrders.length}</span> đơn hàng
             </div>
             <div className="flex items-center gap-2">
               <button 
                 onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                 disabled={currentPage === 1}
                 className="p-1 rounded hover:bg-slate-100 disabled:opacity-50 disabled:cursor-not-allowed text-slate-600 transition-colors"
                 title="Trang trước"
               >
                 <ChevronLeft size={20} />
               </button>
               <span className="text-sm font-medium text-slate-700">Trang {currentPage} / {totalPages}</span>
               <button 
                 onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                 disabled={currentPage === totalPages}
                 className="p-1 rounded hover:bg-slate-100 disabled:opacity-50 disabled:cursor-not-allowed text-slate-600 transition-colors"
                 title="Trang sau"
               >
                 <ChevronRight size={20} />
               </button>
             </div>
          </div>
        )}

      {/* Manual Order Modal */}
      {isCreateModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm p-4">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden">
              <div className="p-4 border-b border-slate-200 flex justify-between items-center bg-slate-50">
                 <h3 className="text-lg font-bold text-slate-800">Tạo đơn hàng mới</h3>
                 <button onClick={() => setIsCreateModalOpen(false)} className="text-slate-400 hover:text-slate-600 p-1"><X size={24}/></button>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-6">
                 {/* Customer Info */}
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                       <label className="block text-sm font-medium text-slate-700 mb-1">Tên khách hàng</label>
                       <div className="relative">
                         <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                         <input 
                           type="text" 
                           value={customerInfo.name}
                           onChange={(e) => setCustomerInfo({...customerInfo, name: e.target.value})}
                           className="w-full pl-9 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                           placeholder="Nhập tên khách..."
                         />
                       </div>
                    </div>
                    <div>
                       <label className="block text-sm font-medium text-slate-700 mb-1">Số điện thoại</label>
                       <input 
                           type="text" 
                           value={customerInfo.phone}
                           onChange={(e) => setCustomerInfo({...customerInfo, phone: e.target.value})}
                           className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                           placeholder="0912..."
                       />
                    </div>
                    <div className="md:col-span-2">
                       <label className="block text-sm font-medium text-slate-700 mb-1">Địa chỉ giao hàng</label>
                       <div className="relative">
                          <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                          <input 
                              type="text" 
                              value={customerInfo.address}
                              onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})}
                              className="w-full pl-9 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                              placeholder="Số nhà, đường, phường, quận..."
                          />
                       </div>
                    </div>
                 </div>

                 {/* Product Selection */}
                 <div className="border-t border-slate-100 pt-4">
                    <h4 className="font-bold text-slate-700 mb-3">Sản phẩm</h4>
                    <div className="relative mb-4">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                          type="text"
                          value={productSearch}
                          onChange={(e) => setProductSearch(e.target.value)}
                          placeholder="Tìm và thêm sản phẩm..."
                          className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                        />
                        {productSearch && (
                           <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-lg max-h-48 overflow-y-auto z-10">
                              {MOCK_PRODUCTS.filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase())).slice(0, 5).map(p => (
                                 <div 
                                    key={p.id} 
                                    onClick={() => handleAddProductToOrder(p)}
                                    className="p-3 hover:bg-indigo-50 cursor-pointer flex items-center gap-3 border-b border-slate-50 last:border-0"
                                 >
                                    <img src={p.image} className="w-12 h-12 rounded object-cover border border-slate-200" />
                                    <div className="flex-1">
                                       <div className="text-sm font-medium">{p.name}</div>
                                       <div className="text-xs text-slate-500">{formatCurrency(p.salePrice || p.price)}</div>
                                    </div>
                                    <Plus size={16} className="text-indigo-600" />
                                 </div>
                              ))}
                           </div>
                        )}
                    </div>

                    <div className="space-y-2">
                       {newOrderItems.map((item) => (
                          <div key={item.product.id} className="flex items-center gap-4 bg-slate-50 p-3 rounded-lg border border-slate-100">
                             <img src={item.product.image} className="w-16 h-16 rounded object-cover border border-slate-200" />
                             <div className="flex-1">
                                <div className="text-sm font-medium">{item.product.name}</div>
                                <div className="text-xs text-slate-500">{item.product.sku}</div>
                             </div>
                             <div className="text-sm font-semibold">{formatCurrency(item.product.salePrice || item.product.price)}</div>
                             <div className="w-16 text-center text-sm font-medium bg-white border border-slate-200 rounded px-2 py-1">
                                x{item.quantity}
                             </div>
                             <button onClick={() => handleRemoveItem(item.product.id)} className="text-red-500 hover:text-red-700 p-1">
                               <X size={16} />
                             </button>
                          </div>
                       ))}
                       {newOrderItems.length === 0 && <div className="text-center text-slate-400 py-4 text-sm">Chưa có sản phẩm nào được chọn</div>}
                    </div>
                 </div>
              </div>

              <div className="p-4 border-t border-slate-200 bg-slate-50 flex justify-between items-center">
                 <div className="text-right flex-1 mr-6">
                    <span className="text-sm text-slate-500 mr-2">Tổng tiền hàng:</span>
                    <span className="text-xl font-bold text-indigo-600">
                      {formatCurrency(newOrderItems.reduce((sum, i) => sum + (i.product.salePrice || i.product.price) * i.quantity, 0))}
                    </span>
                 </div>
                 <button 
                   onClick={handleCreateOrder}
                   className="bg-green-600 hover:bg-green-700 text-white px-6 py-2.5 rounded-lg font-medium shadow-sm transition-colors"
                 >
                   Hoàn tất đơn hàng
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Bulk Print Modal */}
      {isBulkPrintModalOpen && (
         <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm p-4">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden animate-fade-in">
             <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
               <h3 className="font-bold text-slate-800">In Đơn Hàng Loạt</h3>
               <button onClick={() => setIsBulkPrintModalOpen(false)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
             </div>

             <div className="p-6">
                <div className="text-center mb-6">
                    <FileOutput size={48} className="mx-auto text-indigo-200 mb-4" />
                    <p className="text-slate-600 mb-2">Hệ thống đang chuẩn bị phiếu in cho các đơn hàng đã chọn.</p>
                </div>

                <div className="bg-slate-50 p-4 rounded-lg border border-slate-100 mb-6">
                    <div className="flex items-center justify-between mb-2">
                        <span className="text-sm font-medium text-slate-700">Tổng đơn đã chọn:</span>
                        <span className="font-bold text-slate-800">{selectedOrderIds.size} đơn</span>
                    </div>

                    {/* Express Filter in Modal */}
                    <div className="flex items-center justify-between py-2 border-t border-slate-200">
                       <label className="flex items-center gap-2 cursor-pointer">
                          <input 
                            type="checkbox" 
                            checked={bulkPrintIncludeExpress}
                            onChange={(e) => setBulkPrintIncludeExpress(e.target.checked)}
                            className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500"
                          />
                          <span className="text-sm text-slate-700 flex items-center gap-1">
                             <Zap size={14} className="text-red-500 fill-red-500" /> Bao gồm đơn Hỏa tốc
                          </span>
                       </label>
                       <span className="text-xs bg-red-100 text-red-600 px-2 py-0.5 rounded-full font-bold">
                          {Array.from(selectedOrderIds).filter(id => orders.find(o => o.id === id)?.shippingMethod === 'Hỏa tốc').length} đơn
                       </span>
                    </div>
                </div>

                <div className="bg-white border border-slate-200 rounded-lg max-h-40 overflow-y-auto mb-6">
                   {Array.from(selectedOrderIds).map(id => {
                       const order = orders.find(o => o.id === id);
                       const isExpress = order?.shippingMethod === 'Hỏa tốc';

                       if (!bulkPrintIncludeExpress && isExpress) return null;

                       return (
                           <div key={id} className="p-2 border-b border-slate-50 last:border-0 flex justify-between items-center text-sm hover:bg-slate-50">
                               <div className="flex items-center gap-2">
                                  <span>{id}</span>
                                  {isExpress && <Zap size={12} className="text-red-500 fill-red-500" />}
                               </div>
                               <span className="text-xs text-green-600 font-medium">Sẵn sàng in</span>
                           </div>
                       );
